    (void)sig; (void)si;
    ucontext_t *uc = (ucontext_t *)ucontext;
    greg_t *gregs = uc->uc_mcontext.gregs;
    gregs[REG_RIP] &= ~0xf;
    gregs[REG_RIP] -= 0x10;
